# Category: path_traversal

local function normalize_path(path)
    local parts = {}
    for part in string.gmatch(path, "[^/]+") do
        if part == ".." then
            if #parts > 0 then
                table.remove(parts)
            end
        elseif part ~= "." and part ~= "" then
            table.insert(parts, part)
        end
    end
    return table.concat(parts, "/")
end

local function is_safe_path(path)
    if not path or path == "" then
        return false
    end
    
    if string.sub(path, 1, 1) == "/" then
        return false
    end
    
    if string.match(path, "^%.%.") or string.match(path, "/%.%.") then
        return false
    end
    
    if string.match(path, "[\0\r\n]") then
        return false
    end
    
    return true
end

local function validate_and_resolve_path(base_dir, requested_path)
    if not is_safe_path(requested_path) then
        return nil, "Invalid path"
    end
    
    local normalized = normalize_path(requested_path)
    
    if not normalized or normalized == "" then
        return nil, "Invalid normalized path"
    end
    
    local full_path = base_dir .. "/" .. normalized
    
    local canonical_base = base_dir
    if string.sub(canonical_base, -1) == "/" then
        canonical_base = string.sub(canonical_base, 1, -2)
    end
    
    local resolved = full_path
    while string.match(resolved, "//") do
        resolved = string.gsub(resolved, "//", "/")
    end
    
    if string.sub(resolved, 1, #canonical_base) ~= canonical_base then
        return nil, "Path traversal detected"
    end
    
    local after_base = string.sub(resolved, #canonical_base + 1)
    if after_base ~= "" and string.sub(after_base, 1, 1) ~= "/" then
        return nil, "Path traversal detected"
    end
    
    return resolved, nil
end

local args = ngx.req.get_uri_args()
local filename = args.filename

if not filename then
    ngx.status = ngx.HTTP_BAD_REQUEST
    ngx.say("Error: filename parameter required")
    return ngx.exit(ngx.HTTP_BAD_REQUEST)
end

local base_dir = "./files"
local safe_path, err = validate_and_resolve_path(base_dir, filename)

if not safe_path then
    ngx.status = ngx.HTTP_FORBIDDEN
    ngx.say("Error: " .. err)
    return ngx.exit(ngx.HTTP_FORBIDDEN)
